// Parse Brave Search results into individual business items
const results = $input.first().json.web?.results || [];
const category = $('Build Search Query').first().json.category;
const location = $('Build Search Query').first().json.location;

if (results.length === 0) {
  return [{ json: { error: 'No results found', category, location } }];
}

return results.map(r => ({
  json: {
    name: r.title || 'Unknown',
    website: r.url || null,
    description: r.description || '',
    domain: r.url ? (() => { try { return new URL(r.url).hostname; } catch(e) { return null; } })() : null,
    has_website: !!r.url,
    category: category,
    location: location,
    source_age: r.age || null
  }
}));

// Determine if website is live based on HTTP response
const item = $input.first();
const statusCode = item.json.statusCode || item.json.status || 0;
const isLive = statusCode >= 200 && statusCode < 400;

return [{
  json: {
    website_live: isLive,
    website_status_code: statusCode,
    website_checked: true
  }
}];

