// After all batches, compile a summary
const allItems = $input.all();

let strong = 0, moderate = 0, weak = 0;
allItems.forEach(item => {
  const tier = item.json.tier;
  if (tier === 'Strong') strong++;
  else if (tier === 'Moderate') moderate++;
  else if (tier === 'Weak') weak++;
});

const total = allItems.length;
const category = allItems[0]?.json?.category || 'Unknown';
const location = allItems[0]?.json?.location || 'Unknown';

return [{
  json: {
    summary_category: category,
    summary_location: location,
    total_businesses: total,
    strong_count: strong,
    moderate_count: moderate,
    weak_count: weak,
    lead_rate: total > 0 ? Math.round((weak / total) * 100) : 0,
    completed_at: new Date().toISOString()
  }
}];
